77	#[derive(Debug, Clone)]
78	pub struct TrustResolver {
79	    config: TrustConfig,
80	}
81	
82	impl TrustResolver {
83	    #[must_use]
84	    pub fn new(config: TrustConfig) -> Self {
85	        Self { config }
86	    }
87	
88	    #[must_use]
89	    pub fn resolve(&self, cwd: &str, screen_text: &str) -> TrustDecision {
90	        if !detect_trust_prompt(screen_text) {
91	            return TrustDecision::NotRequired;
92	        }
93	
94	        let mut events = vec![TrustEvent::TrustRequired {
95	            cwd: cwd.to_owned(),
96	        }];
97	
98	        if let Some(matched_root) = self
99	            .config
100	            .denied
101	            .iter()
102	            .find(|root| path_matches(cwd, root))
103	        {
104	            let reason = format!("cwd matches denied trust root: {}", matched_root.display());
105	            events.push(TrustEvent::TrustDenied {
106	                cwd: cwd.to_owned(),
107	                reason,
108	            });
109	            return TrustDecision::Required {
110	                policy: TrustPolicy::Deny,
111	                events,
112	            };
113	        }
114	
115	        if self
116	            .config
117	            .allowlisted
118	            .iter()
119	            .any(|root| path_matches(cwd, root))
120	        {
121	            events.push(TrustEvent::TrustResolved {
122	                cwd: cwd.to_owned(),
123	                policy: TrustPolicy::AutoTrust,
124	            });
125	            return TrustDecision::Required {
126	                policy: TrustPolicy::AutoTrust,
127	                events,
128	            };
129	        }
130	
131	        TrustDecision::Required {
132	            policy: TrustPolicy::RequireApproval,
133	            events,
134	        }
135	    }
136	
137	    #[must_use]
138	    pub fn trusts(&self, cwd: &str) -> bool {
139	        !self
140	            .config
141	            .denied
142	            .iter()
143	            .any(|root| path_matches(cwd, root))
144	            && self
145	                .config
146	                .allowlisted
147	                .iter()
148	                .any(|root| path_matches(cwd, root))
149	    }
150	}
