152	#[must_use]
153	pub fn detect_trust_prompt(screen_text: &str) -> bool {
154	    let lowered = screen_text.to_ascii_lowercase();
155	    TRUST_PROMPT_CUES
156	        .iter()
157	        .any(|needle| lowered.contains(needle))
158	}
